import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.next();

        // Vulnerability: Not checking the length of the input before using it in a fixed-size buffer
        byte[] buffer = new byte[10];
        System.arraycopy(input.getBytes(), 0, buffer, 0, input.length());

        System.out.println("Input copied to buffer: " + new String(buffer));
    }
}

