import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Read the entire line instead of using next()

        // Check if the input length exceeds the buffer size
        if (input.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter string.");
            return;
        }

        // Copy input to buffer
        byte[] buffer = new byte[10];
        System.arraycopy(input.getBytes(), 0, buffer, 0, input.length());

        System.out.println("Input copied to buffer: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
